"use client";

import { FormEvent, useState } from "react";

type BannerFormState = {
  projectName: string;
  title: string;
  subtitle: string;
  imageUrl: string;
  ctaLabel: string;
  ctaHref: string;
};

const initialState: BannerFormState = {
  projectName: "Rite Realty",
  title: "",
  subtitle: "",
  imageUrl: "",
  ctaLabel: "Explore Projects",
  ctaHref: "/projects/new-launch",
};

export default function BannerUpdateSection() {
  const [form, setForm] = useState<BannerFormState>(initialState);
  const [message, setMessage] = useState<string>("");
  const [submitting, setSubmitting] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSubmitting(true);
    setMessage("");

    const response = await fetch("/api/banner", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    });

    const data = (await response.json()) as { error?: string };

    if (!response.ok) {
      setMessage(data.error ?? "Could not update banner.");
      setSubmitting(false);
      return;
    }

    setMessage("Banner updated. Refresh the page to see the latest project banner.");
    setForm(initialState);
    setSubmitting(false);
  }

  return (
    <section className="mx-auto mt-10 w-full max-w-7xl px-4 md:px-6">
      <div className="rounded-2xl border border-zinc-200 bg-white p-6 shadow-sm">
        <h2 className="text-2xl font-semibold text-zinc-900">Update Project Banner</h2>
        <p className="mt-2 text-sm text-zinc-600">
          Update the latest homepage banner from backend.
        </p>

        <form onSubmit={handleSubmit} className="mt-6 grid gap-3 md:grid-cols-2">
          <input
            value={form.projectName}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, projectName: event.target.value }))
            }
            placeholder="Project Name"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.title}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, title: event.target.value }))
            }
            placeholder="Banner Title"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.subtitle}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, subtitle: event.target.value }))
            }
            placeholder="Banner Subtitle"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            required
          />
          <input
            value={form.imageUrl}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, imageUrl: event.target.value }))
            }
            placeholder="Background Image URL"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            required
          />
          <input
            value={form.ctaLabel}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, ctaLabel: event.target.value }))
            }
            placeholder="CTA Label"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.ctaHref}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, ctaHref: event.target.value }))
            }
            placeholder="CTA Href"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <button
            type="submit"
            disabled={submitting}
            className="md:col-span-2 rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white transition hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-70"
          >
            {submitting ? "Updating..." : "Update Banner"}
          </button>
        </form>

        {message ? <p className="mt-3 text-sm text-zinc-700">{message}</p> : null}
      </div>
    </section>
  );
}
